create table utenti_tlg.tbl_anag_utenti (
    id_utente          number(38, 0) not null enable,
    nome_utente        varchar2(50 byte),
    user_name          varchar2(100 byte),
    id_profilo         number(38, 0) not null disable,
    id_impresa         number(38, 0),
    e_mail             varchar2(100 byte),
    data_fine_validita date,
    last_login         timestamp(6),
    ldap_account       varchar2(100 byte),
    ruolo_monitoraggio number(*, 0),
    last_ip            varchar2(100 byte),
    id_ruolo_portale   number(*, 0),
    id_aree            varchar2(100 byte),
    copiato_da         varchar2(100 byte)
);

alter table utenti_tlg.tbl_anag_utenti add supplemental log data ( all ) columns;


